from typing import List, Tuple

def recipe_chain_optimization(n: int, recipes: List[Tuple[str, int, Tuple[int, int]]], graph: List[List[int]], min_cal: int, min_protein: int) -> int:
    def dfs(recipe_index: int, memo: dict, current_cal: int, current_protein: int, total_cost: int) -> int:
        if (recipe_index, current_cal, current_protein) in memo:
            return memo[(recipe_index, current_cal, current_protein)]

        name, cost, (calories, protein) = recipes[recipe_index]

        # Calculate the cost of including this recipe
        include_cost = float('inf')
        for parent in graph[recipe_index]:
            include_cost = min(include_cost, dfs(parent, memo, current_cal, current_protein, total_cost))

        if include_cost == float('inf'):
            return float('inf')

        # Total cost including this recipe
        total_cost += cost

        # Check if the current combination meets or exceeds the minimum requirements
        if current_cal + calories >= min_cal and current_protein + protein >= min_protein:
            memo[(recipe_index, current_cal, current_protein)] = include_cost + cost
        else:
            # Continue DFS without including this recipe
            memo[(recipe_index, current_cal, current_protein)] = dfs(recipe_index + 1, memo, current_cal + calories, current_protein + protein, total_cost)

        return memo[(recipe_index, current_cal, current_protein)]

    # Start DFS from each recipe and find the minimum cost
    min_total_cost = float('inf')
    for i in range(n):
        min_total_cost = min(min_total_cost, dfs(i, {}, 0, 0, 0))

    return min_total_cost if min_total_cost != float('inf') else -1

